steps.description:
`set` 只自动合并**第一层**状态，嵌套对象要手动逐层展开很繁琐。用 `immer` 中间件包裹后，可以在 `set` 里**直接改 draft**，immer 负责生成不可变的新状态：

```jsx
import { immer } from 'zustand/middleware/immer'

const useUserStore = create(
  immer((set) => ({
    user: { name: '访客', age: 18 },
    birthday: () => set((s) => { s.user.age += 1 }), // 直接改，无需展开
  })),
)
```

没有 immer 的话，改嵌套的 `user.age` 得写成 `set((s) => ({ user: { ...s.user, age: s.user.age + 1 } }))`——层级越深越痛苦。

> 深入：[Zustand — immer 中间件](https://zustand.docs.pmnd.rs/integrations/immer-middleware)

下面用 immer 存了嵌套的 `user`。补一个「过生日」按钮，调用 `birthday`。

files./App.js:
import { create } from 'zustand'
import { immer } from 'zustand/middleware/immer'

const useUserStore = create(
  immer((set) => ({
    user: { name: '访客', age: 18 },
    birthday: () =>
      set((state) => {
        state.user.age += 1 // immer：直接改 draft，无需手动展开
      }),
  })),
)

export default function App() {
  const { user, birthday } = useUserStore()
  return (
    <div style={{ padding: 12 }}>
      <p>{user.name}，{user.age} 岁</p>
      {/* TODO: 加「过生日」按钮，调用 birthday */}
    </div>
  )
}

