solution./App.js:
import { create } from 'zustand'
import { persist, createJSONStorage } from 'zustand/middleware'

const useStore = create(
  persist(
    (set) => ({
      count: 0,
      inc: () => set((s) => ({ count: s.count + 1 })),
    }),
    {
      name: 'demo-count',
      storage: createJSONStorage(() => localStorage),
    },
  ),
)

export default function App() {
  const { count, inc } = useStore()
  return (
    <div style={{ padding: 12 }}>
      <p>count: {count}</p>
      <button onClick={inc}>+1</button>
    </div>
  )
}

steps.description:
除了在组件里读状态，还能用 `useStore.subscribe(cb)` **订阅**变化。回调在状态变化时执行，但**不会**触发组件重渲染——适合把状态变化转成副作用（提示、埋点、日志、同步等）：

```jsx
useEffect(() => {
  const unsub = useStore.subscribe((state) => {
    console.log('age 变成', state.age)
  })
  return unsub // 清理：取消订阅
}, [])
```

`subscribe` 返回一个取消订阅的函数。在组件里要放进 `useEffect` 并在清理时调用它，防止重复订阅和泄漏。

> 深入：[Zustand — 无需渲染即可订阅](https://zustand.docs.pmnd.rs/guides/updating-state#with-subscribe)

下面想在 `age >= 26` 时更新 `status`。在 `useEffect` 里用 `useStore.subscribe` 监听，并返回取消订阅函数。

files./App.js:
import { useState, useEffect } from 'react'
import { create } from 'zustand'

const useStore = create((set) => ({
  age: 20,
  grow: () => set((s) => ({ age: s.age + 1 })),
}))

export default function App() {
  const age = useStore((s) => s.age)
  const grow = useStore((s) => s.grow)
  const [status, setStatus] = useState('未满 26')
  useEffect(() => {
    // TODO: 用 useStore.subscribe 监听：age >= 26 设为「可以了」，否则「未满 26」，并返回取消订阅函数
    return
  }, [])
  return (
    <div style={{ padding: 12 }}>
      <p>年龄：{age}　状态：{status}</p>
      <button onClick={grow}>长一岁</button>
    </div>
  )
}

solution./App.js:
import { useState, useEffect } from 'react'
import { create } from 'zustand'

const useStore = create((set) => ({
  age: 20,
  grow: () => set((s) => ({ age: s.age + 1 })),
}))

export default function App() {
  const age = useStore((s) => s.age)
  const grow = useStore((s) => s.grow)
  const [status, setStatus] = useState('未满 26')
  useEffect(() => {
    const unsub = useStore.subscribe((state) => {
      setStatus(state.age >= 26 ? '可以了' : '未满 26')
    })
    return unsub
  }, [])
  return (
    <div style={{ padding: 12 }}>
      <p>年龄：{age}　状态：{status}</p>
      <button onClick={grow}>长一岁</button>
    </div>
  )
}
